@@ -509,6 +509,7 @@ struct flb_mp_accessor *flb_mp_accessor_create(struct mk_list *slist_patterns)
  * @return The number of matches found.
  */
 static inline int accessor_key_find_matches(struct flb_mp_accessor *mpa,
+                                            struct flb_mp_accessor_match *matches_table,
                                             msgpack_object *key,
                                             int* matched_indexes)
 {
@@ -520,7 +521,7 @@ static inline int accessor_key_find_matches(struct flb_mp_accessor *mpa,

     count = mk_list_size(&mpa->ra_list);
     for (i = 0; i < count; i++) {
-        match = &mpa->matches[i];
+        match = &matches_table[i];
         if (match->matched == FLB_FALSE) {
             continue;
         }
@@ -535,6 +536,7 @@ static inline int accessor_key_find_matches(struct flb_mp_accessor *mpa,
 }

 static inline int accessor_sub_pack(struct flb_mp_accessor *mpa,
+                                    struct flb_mp_accessor_match *matches_table,
                                     int* matched_indexes,
                                     int match_count,
                                     msgpack_packer *mp_pck,
@@ -549,7 +551,7 @@ static inline int accessor_sub_pack(struct flb_mp_accessor *mpa,
     struct flb_mp_accessor_match *match;

     for (i = 0; i < match_count; i++) {
-        match = &mpa->matches[matched_indexes[i]];
+        match = &matches_table[matched_indexes[i]];
         if (match->key == key || match->key == val) {
             return FLB_FALSE;
         }
@@ -565,7 +567,7 @@ static inline int accessor_sub_pack(struct flb_mp_accessor *mpa,
             k = &val->via.map.ptr[i].key;
             v = &val->via.map.ptr[i].val;

-            ret = accessor_sub_pack(mpa, matched_indexes, match_count, mp_pck, k, v);
+            ret = accessor_sub_pack(mpa, matches_table, matched_indexes, match_count, mp_pck, k, v);
             if (ret == FLB_TRUE) {
                 flb_mp_map_header_append(&mh);
             }
@@ -576,7 +578,7 @@ static inline int accessor_sub_pack(struct flb_mp_accessor *mpa,
         flb_mp_array_header_init(&mh, mp_pck);
         for (i = 0; i < val->via.array.size; i++) {
             v = &val->via.array.ptr[i];
-            ret = accessor_sub_pack(mpa, matched_indexes, match_count, mp_pck, NULL, v);
+            ret = accessor_sub_pack(mpa, matches_table, matched_indexes, match_count, mp_pck, NULL, v);
             if (ret == FLB_TRUE) {
                 flb_mp_array_header_append(&mh);
             }
@@ -620,8 +622,25 @@ int flb_mp_accessor_keys_remove(struct flb_mp_accessor *mpa,
         return FLB_FALSE;
     }

-    /* Reset matches cache */
-    memset(mpa->matches, '\0', mpa->matches_size);
+    /*
+     * Reset matches cache
+     *
+     * This accessor object can be shared by multiple output workers/threads.
+     * The 'matches' array is used as a scratchpad and is mutated by
+     * flb_mp_accessor_keys_remove().
+     *
+     * The previous implementation used a shared scratch buffer (mpa->matches)
+     * which led to data races when the same mpa instance was used concurrently,
+     * causing sporadic/partial key removals.
+     */
+    struct flb_mp_accessor_match *matches_table;
+
+    matches_table = flb_calloc(mk_list_size(&mpa->ra_list),
+                              sizeof(struct flb_mp_accessor_match));
+    if (matches_table == NULL) {
+        flb_errno();
+        return -1;
+    }

     mk_list_foreach(head, &mpa->ra_list) {
         mp_ra = mk_list_entry(head, struct flb_mp_accessor_ra, _head);
@@ -635,7 +654,7 @@ int flb_mp_accessor_keys_remove(struct flb_mp_accessor *mpa,
         ret = flb_ra_get_kv_pair(mp_ra->ra, *map, &s_key, &o_key, &o_val);
         if (ret == 0) {
             /* There is a match, register in the matches table */
-            match = &mpa->matches[rule_id];
+            match = &matches_table[rule_id];
             match->matched = FLB_TRUE;
             match->start_key = s_key;        /* Initial key path that matched */
             match->key = o_key;              /* Final key that matched */
@@ -648,6 +667,7 @@ int flb_mp_accessor_keys_remove(struct flb_mp_accessor *mpa,

     /* If no matches, no modifications were made */
     if (matches == 0) {
+        flb_free(matches_table);
         return FLB_FALSE;
     }

@@ -662,6 +682,7 @@ int flb_mp_accessor_keys_remove(struct flb_mp_accessor *mpa,
     matched_indexes = flb_malloc(sizeof(int) * matches);
     if (!matched_indexes) {
         flb_errno();
+        flb_free(matches_table);
         return -1;
     }

@@ -676,7 +697,8 @@ int flb_mp_accessor_keys_remove(struct flb_mp_accessor *mpa,
          * Find all matching rules that match this 'key'. Return the number of matches or 0
          * if no matches were found. Found matches are stored in the 'matched_indexes' array.
          */
-        ret = accessor_key_find_matches(mpa, key, matched_indexes);
+        /* Use per-call matches table to avoid data races */
+        ret = accessor_key_find_matches(mpa, matches_table, key, matched_indexes);
         if (ret == 0) {
             /* No matches, it's ok to pack the kv pair */
             flb_mp_map_header_append(&mh);
@@ -686,7 +708,7 @@ int flb_mp_accessor_keys_remove(struct flb_mp_accessor *mpa,
         else {
             /* The key has a match. Now we do a step-by-step packaging */

-            ret = accessor_sub_pack(mpa, matched_indexes, ret, &mp_pck, key, val);
+            ret = accessor_sub_pack(mpa, matches_table, matched_indexes, ret, &mp_pck, key, val);
             if (ret == FLB_TRUE) {
                 flb_mp_map_header_append(&mh);
             }
@@ -695,6 +717,7 @@ int flb_mp_accessor_keys_remove(struct flb_mp_accessor *mpa,
     flb_mp_map_header_end(&mh);

     flb_free(matched_indexes);
+    flb_free(matches_table);

     *out_buf = mp_sbuf.data;
     *out_size = mp_sbuf.size;

