  1081→static struct flb_loki *loki_config_create(struct flb_output_instance *ins,
  1082→                                           struct flb_config *config)
  1083→{
  1084→    int ret;
  1085→    int tmp;
  1086→    int io_flags = 0;
  1087→    struct flb_loki *ctx;
  1088→    struct flb_upstream *upstream;
  1089→    char *compress;
  1090→    char *drop_single_key;
  1091→
  1092→    /* Create context */
  1093→    ctx = flb_calloc(1, sizeof(struct flb_loki));
  1094→    if (!ctx) {
  1095→        flb_errno();
  1096→        return NULL;
  1097→    }
  1098→    ctx->ins = ins;
  1099→    flb_loki_kv_init(&ctx->labels_list);
  1100→    flb_loki_kv_init(&ctx->structured_metadata_list);
  1101→    flb_loki_kv_init(&ctx->structured_metadata_map_keys_list);
  1102→
  1103→    /* Register context with plugin instance */
  1104→    flb_output_set_context(ins, ctx);
  1105→
  1106→    /* Set networking defaults */
  1107→    flb_output_net_default(FLB_LOKI_HOST, FLB_LOKI_PORT, ins);
  1108→
  1109→    /* Load config map */
  1110→    ret = flb_output_config_map_set(ins, (void *) ctx);
  1111→    if (ret == -1) {
  1112→        return NULL;
  1113→    }
  1114→
  1115→    /* Initialize final remove_keys list */
  1116→    flb_slist_create(&ctx->remove_keys_derived);
  1117→
  1118→    /* Parse labels */
  1119→    ret = parse_labels(ctx);
  1120→    if (ret == -1) {
  1121→        return NULL;
  1122→    }
  1123→
  1124→    /* Load remove keys */
  1125→    ret = prepare_remove_keys(ctx);
  1126→    if (ret == -1) {
  1127→        return NULL;
  1128→    }
  1129→
  1130→    /* tenant_id_key */
  1131→    if (ctx->tenant_id_key_config) {
  1132→        ctx->ra_tenant_id_key = flb_ra_create(ctx->tenant_id_key_config, FLB_FALSE);
  1133→        if (!ctx->ra_tenant_id_key) {
  1134→            flb_plg_error(ctx->ins,
  1135→                          "could not create record accessor for Tenant ID");
  1136→        }
  1137→    }
  1138→
  1139→    /* Compress (gzip) */
  1140→    compress = (char *) flb_output_get_property("compress", ins);
  1141→    ctx->compress_gzip = FLB_FALSE;
  1142→    if (compress) {
  1143→        if (strcasecmp(compress, "gzip") == 0) {
  1144→            ctx->compress_gzip = FLB_TRUE;
  1145→        }
  1146→    }
  1147→
  1148→    /* Drop Single Key */
  1149→    drop_single_key = (char *) flb_output_get_property("drop_single_key", ins);
  1150→    ctx->out_drop_single_key = FLB_LOKI_DROP_SINGLE_KEY_OFF;
  1151→    if (drop_single_key) {
  1152→        if (strcasecmp(drop_single_key, "raw") == 0) {
  1153→            ctx->out_drop_single_key = FLB_LOKI_DROP_SINGLE_KEY_ON | FLB_LOKI_DROP_SINGLE_KEY_RAW;
  1154→        }
  1155→        else {
  1156→            tmp = flb_utils_bool(drop_single_key);
  1157→            if (tmp == FLB_TRUE) {
  1158→                ctx->out_drop_single_key = FLB_LOKI_DROP_SINGLE_KEY_ON;
  1159→            }
  1160→            else if (tmp == FLB_FALSE) {
  1161→                ctx->out_drop_single_key = FLB_LOKI_DROP_SINGLE_KEY_OFF;
  1162→            }
  1163→            else {
  1164→                flb_plg_error(ctx->ins, "invalid 'drop_single_key' value: %s",
  1165→                              ctx->drop_single_key);
  1166→                return NULL;
  1167→            }
  1168→        }
  1169→    }
  1170→
  1171→    /* Line Format */
  1172→    if (strcasecmp(ctx->line_format, "json") == 0) {
  1173→        ctx->out_line_format = FLB_LOKI_FMT_JSON;
  1174→    }
  1175→    else if (strcasecmp(ctx->line_format, "key_value") == 0) {
  1176→        ctx->out_line_format = FLB_LOKI_FMT_KV;
  1177→    }
  1178→    else {
  1179→        flb_plg_error(ctx->ins, "invalid 'line_format' value: %s",
  1180→                      ctx->line_format);
  1181→        return NULL;
  1182→    }
  1183→
  1184→    /* use TLS ? */
  1185→    if (ins->use_tls == FLB_TRUE) {
  1186→        io_flags = FLB_IO_TLS;
  1187→    }
  1188→    else {
  1189→        io_flags = FLB_IO_TCP;
  1190→    }
  1191→
  1192→    if (ins->host.ipv6 == FLB_TRUE) {
  1193→        io_flags |= FLB_IO_IPV6;
  1194→    }
  1195→
  1196→    /* Create Upstream connection context */
  1197→    upstream = flb_upstream_create(config,
  1198→                                   ins->host.name,
  1199→                                   ins->host.port,
  1200→                                   io_flags,
  1201→                                   ins->tls);
  1202→    if (!upstream) {
  1203→        return NULL;
  1204→    }
  1205→    ctx->u = upstream;
  1206→    flb_output_upstream_set(ctx->u, ins);
  1207→    ctx->tcp_port = ins->host.port;
  1208→    ctx->tcp_host = ins->host.name;
  1209→
  1210→    return ctx;
  1211→}
