  1214→ * Convert struct flb_tm timestamp value to nanoseconds and then it pack it as
  1215→ * a string.
  1216→ */
  1217→static void pack_timestamp(msgpack_packer *mp_pck, struct flb_time *tms)
  1218→{
  1219→    int len;
  1220→    char buf[64];
  1221→    uint64_t nanosecs;
  1222→
  1223→    /* convert to nanoseconds */
  1224→    nanosecs = flb_time_to_nanosec(tms);
  1225→
  1226→    /* format as a string */
  1227→    len = snprintf(buf, sizeof(buf) - 1, "%" PRIu64, nanosecs);
  1228→
  1229→    /* pack the value */
  1230→    msgpack_pack_str(mp_pck, len);
  1231→    msgpack_pack_str_body(mp_pck, buf, len);
  1232→}
