cat > /testbed/tests/internal/mp_race_remove_keys.c <<'EOF'
#include <pthread.h>
#include <msgpack.h>
#include <fluent-bit/flb_mp.h>
#include <fluent-bit/flb_slist.h>
#include <fluent-bit/flb_mem.h>

/*
 * Regression test:
 * flb_mp_accessor_keys_remove() used a shared mutable scratch buffer
 * (mpa->matches) which is not thread-safe. Concurrent use could produce
 * sporadic/partial removals.
 */

#define THREADS 8
#define ITERS   2000

static struct flb_mp_accessor *mpa;
static void *worker(void *arg)
{
    int i;
    int ret;
    void *out_buf;
    size_t out_size;
    size_t off;
    msgpack_unpacked result;
    msgpack_object obj;

    (void) arg;

    for (i = 0; i < ITERS; i++) {
        /* Build a record like {"log":"message","kubernetes":{...},"severity":"warn","k8s_cluster_name":"cls01"} */
        msgpack_sbuffer sbuf;
        msgpack_packer pck;

        msgpack_sbuffer_init(&sbuf);
        msgpack_packer_init(&pck, &sbuf, msgpack_sbuffer_write);

        msgpack_pack_map(&pck, 4);

        msgpack_pack_str(&pck, 3);
        msgpack_pack_str_body(&pck, "log", 3);
        msgpack_pack_str(&pck, 7);
        msgpack_pack_str_body(&pck, "message", 7);

        msgpack_pack_str(&pck, 10);
        msgpack_pack_str_body(&pck, "kubernetes", 10);
        msgpack_pack_map(&pck, 1);
        msgpack_pack_str(&pck, 8);
        msgpack_pack_str_body(&pck, "pod_name", 8);
        msgpack_pack_str(&pck, 10);
        msgpack_pack_str_body(&pck, "pod-name-01", 10);

        msgpack_pack_str(&pck, 8);
        msgpack_pack_str_body(&pck, "severity", 8);
        msgpack_pack_str(&pck, 4);
        msgpack_pack_str_body(&pck, "warn", 4);

        msgpack_pack_str(&pck, 15);
        msgpack_pack_str_body(&pck, "k8s_cluster_name", 15);
        msgpack_pack_str(&pck, 5);
        msgpack_pack_str_body(&pck, "cls01", 5);

        /* Decode into msgpack_object */
        msgpack_unpacked_init(&result);
        off = 0;
        ret = msgpack_unpack_next(&result, sbuf.data, sbuf.size, &off);
        if (ret != MSGPACK_UNPACK_SUCCESS) {
            msgpack_sbuffer_destroy(&sbuf);
            msgpack_unpacked_destroy(&result);
            return (void *) 1;
        }

        obj = result.data;

        out_buf = NULL;
        out_size = 0;
        ret = flb_mp_accessor_keys_remove(mpa, &obj, &out_buf, &out_size);
        if (ret != FLB_TRUE) {
            msgpack_sbuffer_destroy(&sbuf);
            msgpack_unpacked_destroy(&result);
            return (void *) 2;
        }

        /* Verify removed keys are not present */
        msgpack_unpacked_destroy(&result);
        msgpack_unpacked_init(&result);
        off = 0;
        ret = msgpack_unpack_next(&result, out_buf, out_size, &off);
        if (ret != MSGPACK_UNPACK_SUCCESS) {
            flb_free(out_buf);
            msgpack_sbuffer_destroy(&sbuf);
            msgpack_unpacked_destroy(&result);
            return (void *) 3;
        }

        obj = result.data;
        if (obj.type != MSGPACK_OBJECT_MAP || obj.via.map.size != 1) {
            flb_free(out_buf);
            msgpack_sbuffer_destroy(&sbuf);
            msgpack_unpacked_destroy(&result);
            return (void *) 4;
        }

        /* single key must be 'log' */
        if (obj.via.map.ptr[0].key.type != MSGPACK_OBJECT_STR ||
            obj.via.map.ptr[0].key.via.str.size != 3 ||
            strncmp(obj.via.map.ptr[0].key.via.str.ptr, "log", 3) != 0) {
            flb_free(out_buf);
            msgpack_sbuffer_destroy(&sbuf);
            msgpack_unpacked_destroy(&result);
            return (void *) 5;
        }

        flb_free(out_buf);
        msgpack_sbuffer_destroy(&sbuf);
        msgpack_unpacked_destroy(&result);
    }

    return NULL;
}

int main(void)
{
    int i;
    int ret;
    pthread_t threads[THREADS];
    struct mk_list patterns;

    mk_list_init(&patterns);
    flb_slist_add(&patterns, "$kubernetes");
    flb_slist_add(&patterns, "$severity");
    flb_slist_add(&patterns, "$k8s_cluster_name");

    mpa = flb_mp_accessor_create(&patterns);
    if (mpa == NULL) {
        return 1;
    }

    for (i = 0; i < THREADS; i++) {
        ret = pthread_create(&threads[i], NULL, worker, NULL);
        if (ret != 0) {
            return 2;
        }
    }

    for (i = 0; i < THREADS; i++) {
        void *retval;
        pthread_join(threads[i], &retval);
        if (retval != NULL) {
            return (int) (uintptr_t) retval;
        }
    }

    flb_mp_accessor_destroy(mpa);
    flb_slist_destroy(&patterns);

    return 0;
}
